package CWT;

public class JavaConditionalState {

	public static void main(String[] args) {
		
		// TODO Auto-generated method stub

		
		int age = 18;
		
		if(age >=18)
		{
			
		
		System.out.println("Eligible for licesnse");
		}
		else {
			System.out.println("Not Eligible For License");
			}
		
		//For loop
		for(int i = 1; i<=10;i++)
		{
			System.out.print(i);
		}
		
		//While Loop
		
		int i = 1;
		while(i<=5)
		{
			System.out.println(i);
			i++;
		}
	}

}
